1	//! AST-walking evaluator.
2	
3	use mlpl_array::{DenseArray, Shape};
4	use mlpl_parser::{BinOpKind, Expr};
5	use mlpl_trace::{Trace, TraceEvent, TraceValue};
6	
7	use crate::env::Environment;
8	use crate::error::EvalError;
9	
10	/// Evaluate a program (list of statements). Returns the last result.
11	pub fn eval_program(stmts: &[Expr], env: &mut Environment) -> Result<DenseArray, EvalError> {
12	    if stmts.is_empty() {
13	        return Err(EvalError::EmptyInput);
14	    }
15	    let mut trace: Option<&mut Trace> = None;
16	    let mut result = None;
17	    for stmt in stmts {
18	        result = Some(eval_expr(stmt, env, &mut trace)?);
19	    }
20	    result.ok_or(EvalError::EmptyInput)
21	}
22	
23	/// Evaluate a program with tracing enabled.
24	pub fn eval_program_traced(
25	    stmts: &[Expr],
26	    env: &mut Environment,
27	    trace: &mut Trace,
28	) -> Result<DenseArray, EvalError> {
29	    if stmts.is_empty() {
30	        return Err(EvalError::EmptyInput);
31	    }
32	    let mut trace: Option<&mut Trace> = Some(trace);
33	    let mut result = None;
34	    for stmt in stmts {
35	        result = Some(eval_expr(stmt, env, &mut trace)?);
36	    }
37	    result.ok_or(EvalError::EmptyInput)
38	}
39	
40	fn eval_expr(
41	    expr: &Expr,
42	    env: &mut Environment,
43	    trace: &mut Option<&mut Trace>,
44	) -> Result<DenseArray, EvalError> {
45	    let (op_name, inputs, result) = match expr {
46	        Expr::IntLit(n, _) => ("literal", vec![], DenseArray::from_scalar(*n as f64)),
47	        Expr::FloatLit(f, _) => ("literal", vec![], DenseArray::from_scalar(*f)),
48	        Expr::Ident(name, _) => {
49	            let r = env
50	                .get(name)
51	                .cloned()
52	                .ok_or_else(|| EvalError::UndefinedVariable(name.clone()))?;
53	            ("ident", vec![], r)
54	        }
55	        Expr::ArrayLit(elems, _) => ("array_lit", vec![], eval_array_lit(elems, env, trace)?),
56	        Expr::UnaryNeg { operand, .. } => {
57	            let val = eval_expr(operand, env, trace)?;
58	            let r = DenseArray::from_scalar(-1.0).apply_binop(&val, |a, b| a * b)?;
59	            ("negate", vec![TraceValue::from_array(&val)], r)
60	        }
61	        Expr::Assign { name, value, .. } => {
62	            let val = eval_expr(value, env, trace)?;
63	            env.set(name.clone(), val.clone());
64	            ("assign", vec![TraceValue::from_array(&val)], val)
65	        }
66	        Expr::BinOp { op, lhs, rhs, .. } => eval_binop(op, lhs, rhs, env, trace)?,
67	        Expr::FnCall { name, args, .. } => eval_fncall(name, args, env, trace)?,
68	        Expr::Repeat { count, body, .. } => {
69	            let n_arr = eval_expr(count, env, trace)?;
70	            if n_arr.rank() != 0 {
71	                return Err(EvalError::InvalidRepeatCount);
72	            }
73	            let n = n_arr.data()[0] as usize;
74	            let mut r = DenseArray::from_scalar(0.0);
75	            for _ in 0..n {
76	                for stmt in body {
77	                    r = eval_expr(stmt, env, trace)?;
78	                }
79	            }
80	            ("repeat", vec![], r)
81	        }
82	    };
83	    record_trace(trace, op_name, expr.span(), inputs, &result);
84	    Ok(result)
85	}
86	
87	fn record_trace(
88	    trace: &mut Option<&mut Trace>,
89	    op: &str,
90	    span: mlpl_core::Span,
91	    inputs: Vec<TraceValue>,
92	    result: &DenseArray,
93	) {
94	    if let Some(t) = trace.as_mut() {
95	        let seq = t.events().len() as u64;
96	        t.push(TraceEvent {
97	            seq,
98	            op: op.into(),
99	            span,
100	            inputs,
101	            output: TraceValue::from_array(result),
102	        });
103	    }
104	}
105	
106	fn eval_binop(
107	    op: &BinOpKind,
108	    lhs: &Expr,
109	    rhs: &Expr,
110	    env: &mut Environment,
111	    trace: &mut Option<&mut Trace>,
112	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
113	    let l = eval_expr(lhs, env, trace)?;
114	    let r = eval_expr(rhs, env, trace)?;
115	    let (name, f): (&str, fn(f64, f64) -> f64) = match op {
116	        BinOpKind::Add => ("add", |a, b| a + b),
117	        BinOpKind::Sub => ("sub", |a, b| a - b),
118	        BinOpKind::Mul => ("mul", |a, b| a * b),
119	        BinOpKind::Div => ("div", |a, b| a / b),
120	    };
121	    let inputs = vec![TraceValue::from_array(&l), TraceValue::from_array(&r)];
122	    let result = l.apply_binop(&r, f)?;
123	    Ok((name, inputs, result))
124	}
125	
126	fn eval_fncall(
127	    name: &str,
128	    args: &[Expr],
129	    env: &mut Environment,
130	    trace: &mut Option<&mut Trace>,
131	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
132	    let evaluated: Vec<DenseArray> = args
133	        .iter()
134	        .map(|a| eval_expr(a, env, trace))
135	        .collect::<Result<Vec<_>, _>>()?;
136	    let inputs: Vec<TraceValue> = evaluated.iter().map(TraceValue::from_array).collect();
137	    let result = mlpl_runtime::call_builtin(name, evaluated)?;
138	    Ok(("fncall", inputs, result))
139	}
140	
141	fn eval_array_lit(
142	    elems: &[Expr],
143	    env: &mut Environment,
144	    trace: &mut Option<&mut Trace>,
145	) -> Result<DenseArray, EvalError> {
146	    if elems.is_empty() {
147	        return Ok(DenseArray::from_vec(vec![]));
148	    }
149	    let evaluated: Vec<DenseArray> = elems
